	user: ReturnType<typeof userEvent.setup>,
	trigger: RegExp | string = /send feedback/i,
) {
	await user.click(screen.getByRole("button", { name: trigger }));
	return await screen.findByRole("dialog");
}

beforeEach(() => {
	captureMock.mockReset();
});

